const questions=[{category:"MySQL",question:"Quelle fonction renvoie la date et l'heure actuelles ?",options:["<code>NOW()</code>","<code>CURRENT_DATE()</code>","<code>GETDATE()</code>","<code>SYSDATE()</code>"],answer:0,explanation:"<code>NOW()</code> retourne date et heure au format YYYY-MM-DD HH:MM:SS."},{category:"MySQL",question:"Quelle commande sauvegarde une base de donnees ?",options:["<code>BACKUP DATABASE</code>","<code>DUMP DATABASE</code>","<code>SAVE DATABASE</code>","<code>EXPORT DATABASE</code>"],answer:0,explanation:"<code>BACKUP DATABASE</code> cree une sauvegarde."},{category:"MySQL",question:"Quelle commande modifie la structure d'une table ?",options:["<code>ALTER TABLE</code>","<code>MODIFY TABLE</code>","<code>CHANGE TABLE</code>","<code>EDIT TABLE</code>"],answer:0,explanation:"<code>ALTER TABLE</code> modifie la structure."},{category:"MySQL",question:"Quelle commande ajoute une colonne ?",options:["<code>ADD COLUMN</code>","<code>ALTER TABLE</code>","<code>CHANGE COLUMN</code>","<code>INSERT COLUMN</code>"],answer:1,explanation:"<code>ALTER TABLE table ADD colonne type;</code>"},{category:"MySQL",question:"Quelle commande evite les doublons ?",options:["<code>DISTINCT</code>","<code>UNIQUE</code>","<code>DIFFERENT</code>","<code>NO_DUPLICATES</code>"],answer:0,explanation:"<code>SELECT DISTINCT</code> elimine les doublons."},{category:"MySQL",question:"Quelle commande definit une procedure stockee ?",options:["<code>CREATE PROCEDURE</code>","<code>ADD PROCEDURE</code>","<code>DEFINE PROCEDURE</code>","<code>MAKE PROCEDURE</code>"],answer:0,explanation:"<code>CREATE PROCEDURE nom() BEGIN...END;</code>"},{category:"MySQL",question:"Quelle commande definit une vue ?",options:["<code>CREATE VIEW</code>","<code>DEFINE VIEW</code>","<code>NEW VIEW</code>","<code>ADD VIEW</code>"],answer:0,explanation:"<code>CREATE VIEW nom AS SELECT...</code>"},{category:"MySQL",question:"Quelle commande affiche toutes les colonnes ?",options:["<code>SHOW COLUMNS</code>","<code>LIST COLUMNS</code>","<code>DISPLAY COLUMNS</code>","<code>SELECT * FROM</code>"],answer:3,explanation:"<code>SELECT * FROM table</code> affiche tout."},{category:"HTML",question:"Alternative de <code>&lt;b&gt;</code> pour le gras ?",options:["<code>&lt;bold&gt;</code>","<code>&lt;strong&gt;</code>","<code>&lt;i&gt;</code>","<code>&lt;emp&gt;</code>"],answer:1,explanation:"<code>&lt;strong&gt;</code> est l'alternative semantique."},{category:"HTML",question:"Role des balises <code>&lt;Hn&gt;</code> ?",options:["Ligne horizontale","Titres de differents niveaux","Texte de tailles differentes","Texte a distance du bord"],answer:1,explanation:"H1 a H6 definissent des niveaux de titres."},{category:"HTML",question:"Difference entre H4 et H6 ?",options:["H4 plus grand que H6","H4 plus petit que H6","Meme taille","H4 italique, H6 gras"],answer:0,explanation:"H4 est plus grand que H6 (H1 = plus grand)."},{category:"HTML",question:"Comment creer un lien email ?",options:["<code>&lt;a href=\"mailto:x@y\"&gt;</code>","<code>&lt;a href=\"x@y\"&gt;</code>","<code>Mail&gt;x@y</code>","<code>Mail href=\"x@y\"</code>"],answer:0,explanation:"<code>mailto:</code> ouvre le client email."},{category:"HTML",question:"Pour indiquer un contenu tres important :",options:["<code>&lt;strong&gt;</code>","<code>&lt;em&gt;</code>","<code>&lt;mark&gt;</code>"],answer:0,explanation:"<code>&lt;strong&gt;</code> = importance forte."},{category:"HTML",question:"Pour fixer le fond lors du defilement :",options:["BGPROPERTIES=\"nomove\"","BGPROPERTIES=\"stop\"","BGPROPERTIES=\"stick\"","BGPROPERTIES=\"fixed\""],answer:3,explanation:"En CSS moderne : <code>background-attachment: fixed;</code>"},{category:"HTML",question:"<code>&lt;a name=\"pub\"&gt;&lt;/a&gt;</code> definit :",options:["Un lien hypertexte","Une destination (signet)","Un lien vers la page pub"],answer:1,explanation:"<code>name</code> cree un signet/ancre."},{category:"HTML",question:"Quelle balise pour un lien de navigation ?",options:["<code>&lt;nav&gt;</code>","<code>&lt;link&gt;</code>","<code>&lt;a&gt;</code>","<code>&lt;menu&gt;</code>"],answer:2,explanation:"<code>&lt;a&gt;</code> cree un lien hypertexte."},{category:"CSS",question:"Propriete pour la couleur de bordure ?",options:["<code>border-color</code>","<code>border-style</code>","<code>border-width</code>","<code>border-radius</code>"],answer:0,explanation:"<code>border-color</code> definit la couleur."},{category:"CSS",question:"Propriete pour l'opacite ?",options:["<code>opacity</code>","<code>visibility</code>","<code>filter</code>","<code>background-opacity</code>"],answer:0,explanation:"<code>opacity</code> : 0=transparent, 1=opaque."},{category:"CSS",question:"Alignement vertical dans une grille ?",options:["<code>align-content</code>","<code>justify-content</code>","<code>align-items</code>","<code>align-self</code>"],answer:2,explanation:"<code>align-items</code> aligne verticalement."},{category:"CSS",question:"Espacement entre lignes de grille ?",options:["<code>grid-gap</code>","<code>row-gap</code>","<code>column-gap</code>","<code>gap</code>"],answer:1,explanation:"<code>row-gap</code> espace les lignes."},{category:"CSS",question:"Degrade de couleur en fond ?",options:["<code>background-image</code>","<code>background-color</code>","<code>background-gradient</code>","<code>gradient</code>"],answer:0,explanation:"<code>background-image: linear-gradient(...);</code>"},{category:"CSS",question:"Espacement entre caracteres ?",options:["<code>letter-spacing</code>","<code>word-spacing</code>","<code>line-height</code>","<code>text-spacing</code>"],answer:0,explanation:"<code>letter-spacing</code> controle l'espace entre caracteres."},{category:"CSS",question:"Alignement horizontal dans une grille ?",options:["<code>justify-content</code>","<code>align-items</code>","<code>align-content</code>","<code>justify-items</code>"],answer:0,explanation:"<code>justify-content</code> aligne horizontalement."},{category:"CSS",question:"Espacement entre lignes de texte ?",options:["<code>line-height</code>","<code>letter-spacing</code>","<code>word-spacing</code>","<code>text-spacing</code>"],answer:0,explanation:"<code>line-height</code> definit la hauteur de ligne."},{category:"JavaScript",question:"Objet au sommet de la hierarchie JS ?",options:["<code>url</code>","<code>top</code>","<code>window</code>","<code>document</code>"],answer:2,explanation:"<code>window</code> est l'objet global."},{category:"JavaScript",question:"Plus grand nombre entre a et b ?",options:["<code>Math.ceil(a,b)</code>","<code>Math.max(a,b)</code>","<code>ceil(a,b)</code>","<code>top(a,b)</code>"],answer:1,explanation:"<code>Math.max()</code> retourne le plus grand."},{category:"JavaScript",question:"Commentaire en JavaScript ?",options:["<code>//commentaire</code>","<code>\"commentaire\"</code>","<code>&lt;!--commentaire--&gt;</code>","<code>#commentaire</code>"],answer:0,explanation:"<code>//</code> pour une ligne, <code>/* */</code> multi-lignes."},{category:"JavaScript",question:"JavaScript est identique a Java ?",options:["Vrai","Faux"],answer:1,explanation:"Deux langages completement differents."},{category:"JavaScript",question:"Arrondir 3.12 a l'entier proche ?",options:["<code>Math.round(3.12)</code>","<code>Math.rnd(3.12)</code>","<code>float(3.12)</code>","<code>Math.float(3.12)</code>"],answer:0,explanation:"<code>Math.round(3.12)</code> retourne 3."},{category:"JavaScript",question:"Syntaxe correcte de while ?",options:["<code>while(i&lt;=5)</code>","<code>while i=1 to 5</code>","<code>while(i&lt;=5;i++)</code>","<code>while(i=0;i&lt;=5;i++)</code>"],answer:0,explanation:"<code>while(condition){...}</code>"},{category:"JavaScript",question:"Ouvrir une nouvelle fenetre f2 ?",options:["<code>window.new(\"url\")</code>","<code>window.open(\"url\")</code>","<code>document.open(\"url\")</code>","<code>document.new(\"url\")</code>"],answer:1,explanation:"<code>window.open()</code> ouvre une fenetre."},{category:"JavaScript",question:"Tableau en JavaScript ?",options:["<code>var f=1=(\"a\")</code>","<code>var f=(1:\"a\",2:\"b\")</code>","<code>var f=\"a\",\"b\"</code>","<code>var f=[\"a\",\"b\"]</code>"],answer:3,explanation:"Crochets <code>[]</code> pour les tableaux."},{category:"PHP",question:"CMS populaire en PHP ?",options:["WordPress","Joomla","Magento","Drupal"],answer:0,explanation:"WordPress = CMS PHP le plus populaire."},{category:"PHP",question:"Framework populaire en PHP ?",options:["Symfony","Laravel","CakePHP","CodeIgniter"],answer:1,explanation:"Laravel est le plus populaire actuellement."},{category:"PHP",question:"Namespaces disponibles depuis ?",options:["PHP 2","PHP 4","PHP 5","PHP 6"],answer:2,explanation:"Namespaces depuis PHP 5.3 (2009)."},{category:"PHP",question:"Portee non supportee en PHP ?",options:["<code>static</code>","<code>final</code>","<code>public</code>","<code>friendly</code>"],answer:3,explanation:"<code>friendly</code> n'existe pas en PHP."},{category:"PHP",question:"Variables de classe sont appelees :",options:["Des attributs","Des proprietes","Des instances","Toutes correctes"],answer:1,explanation:"Officiellement : proprietes."},{category:"PHP",question:"Definir une constante ?",options:["<code>constant MAX=\"100\";</code>","<code>const $MAX=\"100\";</code>","<code>constant MAX='100';</code>","<code>const MAX='100';</code>"],answer:3,explanation:"<code>const MAX='100';</code> est correct."},{category:"PHP",question:"Invoquer une methode ?",options:["<code>$object-&gt;maMethod();</code>","<code>object-&gt;maMethod();</code>","<code>object::maMethod();</code>","<code>$object::maMethod();</code>"],answer:0,explanation:"<code>$object-&gt;methode()</code> avec <code>$</code> et <code>-&gt;</code>."}];
let currentQuestion=0,score=0,selectedOption=-1,answered=false,shuffledQuestions=[],answers=[],timerInterval=null,timerSeconds=0;function startTimer(){timerSeconds=0;clearInterval(timerInterval);timerInterval=setInterval(()=>{timerSeconds++;document.getElementById('timer').textContent=String(Math.floor(timerSeconds/60)).padStart(2,'0')+':'+String(timerSeconds%60).padStart(2,'0');},1000);}function stopTimer(){clearInterval(timerInterval);}function shuffle(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;}function startQuiz(){shuffledQuestions=shuffle(questions);currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}function showQuestion(){selectedOption=-1;answered=false;const q=shuffledQuestions[currentQuestion],t=shuffledQuestions.length;document.getElementById('progress-text').textContent=`Question ${currentQuestion+1} / ${t}`;document.getElementById('progress-fill').style.width=((currentQuestion+1)/t*100)+'%';document.getElementById('btn-validate').style.display='inline-block';document.getElementById('btn-validate').disabled=true;document.getElementById('btn-next').style.display='none';let h=`<span class="category-badge cat-${q.category.toLowerCase()}">${q.category}</span><div class="question-text">${q.question}</div><ul class="options">`;q.options.forEach((o,i)=>{h+=`<li onclick="selectOption(${i})">${o}</li>`;});h+=`</ul><div class="explanation" id="explanation">${q.explanation}</div>`;document.getElementById('question-card').innerHTML=h;}function selectOption(i){if(answered)return;selectedOption=i;document.getElementById('btn-validate').disabled=false;document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.toggle('selected',x===i);});}function validateAnswer(){if(selectedOption===-1||answered)return;answered=true;const q=shuffledQuestions[currentQuestion],c=q.answer,ok=selectedOption===c;if(ok)score++;answers.push({question:q,selected:selectedOption,correct:ok});document.querySelectorAll('.options li').forEach((e,x)=>{e.classList.add('disabled');if(x===c)e.classList.add('correct');if(x===selectedOption&&!ok)e.classList.add('wrong');});document.getElementById('explanation').style.display='block';document.getElementById('btn-validate').style.display='none';if(currentQuestion<shuffledQuestions.length-1)document.getElementById('btn-next').style.display='inline-block';else setTimeout(showResults,800);}function nextQuestion(){currentQuestion++;showQuestion();}function showResults(){stopTimer();document.getElementById('quiz-area').style.display='none';const r=document.getElementById('results');r.style.display='block';const t=shuffledQuestions.length,p=Math.round(score/t*100);let lc,m,d;if(p>=80){lc='level-excellent';m='Excellent !';d='Solide base.';}else if(p>=60){lc='level-good';m='Bon niveau !';d='Revoyez les erreurs.';}else if(p>=40){lc='level-average';m='Moyen.';d='Travaillez vos points faibles.';}else{lc='level-weak';m='A renforcer.';d='Reprenez les bases.';}const cats=['MySQL','HTML','CSS','JavaScript','PHP'];const cs={};cats.forEach(c=>cs[c]={total:0,correct:0});answers.forEach(a=>{cs[a.question.category].total++;if(a.correct)cs[a.question.category].correct++;});let ch='<div class="cat-scores">';cats.forEach(c=>{const s=cs[c],pc=s.total>0?Math.round(s.correct/s.total*100):0;let co='#e74c3c';if(pc>=80)co='#27ae60';else if(pc>=60)co='#2980b9';else if(pc>=40)co='#f39c12';ch+=`<div class="cat-score-card"><div class="cat-name"><span class="category-badge cat-${c.toLowerCase()}">${c}</span></div><div class="cat-pct" style="color:${co}">${pc}%</div><div class="cat-detail">${s.correct}/${s.total}</div></div>`;});ch+='</div>';r.innerHTML=`<div class="score-circle ${lc}">${p}%<span class="label">${score}/${t}</span></div><div class="level-message">${m}</div><div class="level-detail">${d}</div>${ch}<div class="btn-container" style="margin-top:30px"><button class="btn btn-primary" onclick="startQuiz()">Recommencer</button><button class="btn btn-restart" onclick="retryFailed()" style="margin-left:10px">Retravailler mes erreurs</button><button class="btn btn-restart" onclick="location.href='/dashboard'" style="margin-left:10px">Accueil</button></div>`;fetch('/api/scores',{method:'POST',headers:{'Content-Type':'application/json','X-CSRF-TOKEN':document.querySelector('meta[name=csrf-token]').content},body:JSON.stringify({qcm_name:'qcm10',score,total:t,percentage:p,duration_seconds:timerSeconds})});}function retryFailed(){const f=answers.filter(a=>!a.correct);if(!f.length){alert('Aucune erreur !');return;}shuffledQuestions=f.map(x=>({...x.question}));currentQuestion=0;score=0;answers=[];document.getElementById('start-screen').style.display='none';document.getElementById('quiz-area').style.display='block';document.getElementById('results').style.display='none';showQuestion();startTimer();}
</script>
